#!/usr/bin/env node
"use strict";

/**
 * Script d'intégration automatique LISA — production readiness
 * Usage : node apply-lisa-prod-files.js
 * À exécuter depuis la racine du projet lisa-formation.
 *
 * Ce script NE FAIT PAS : npm install, npm run build, git add/commit/push.
 * Le contenu de chaque fichier est encodé en base64 pour garantir une
 * intégrité parfaite (plusieurs fichiers contiennent des backticks et des
 * template literals ${...} qui casseraient un script écrit autrement).
 */

const fs = require('fs');
const path = require('path');

const ROOT = __dirname;

function ensureDir(filePath) {
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
}

function writeFileFromBase64(relPath, base64Content) {
  const fullPath = path.join(ROOT, relPath);
  ensureDir(fullPath);
  const buffer = Buffer.from(base64Content, 'base64');
  fs.writeFileSync(fullPath, buffer);
  console.log('\u2705 Créé/remplacé : ' + relPath);
}

function deleteIfExists(relPath) {
  const fullPath = path.join(ROOT, relPath);
  if (fs.existsSync(fullPath)) {
    fs.unlinkSync(fullPath);
    console.log('\u2705 Supprimé : ' + relPath);
  } else {
    console.log('\u2139\ufe0f  Déjà absent (rien à supprimer) : ' + relPath);
  }
}

